/*
 * NOTE:
 * - these get_ routines MUST return data that will not be freed (ie,
 *   use static variables or persistent data).  It will be copied, if
 *   needed, immediately after the get_ routine has been called.
 * - these SET routines must copy the incoming data and can not take
 *   ownership of the memory passed in by the val pointer.
 */
/** XXX: return a data pointer to the data for the dot1qStaticMulticastStaticEgressPorts column and set
         ret_len to its proper size in bytes. */
      char *get_dot1qStaticMulticastStaticEgressPorts(void *data_context, size_t *ret_len) {
         tpgroup_entry_t *ourstGrp = (tpgroup_entry_t *) data_context;
       *ret_len = SYS_USER_PORTMASK_LEN;
        return (u_char*)&ourstGrp->upmsk_st;
      }
/** XXX: Set the value of the dot1qStaticMulticastStaticEgressPorts column and return
         SNMP_ERR_NOERROR on success
         SNMP_ERR_XXX     for SNMP deterministic error codes
         SNMP_ERR_GENERR  on generic failures (a last result response). */
      int set_dot1qStaticMulticastStaticEgressPorts(void *data_context, char *val, size_t val_len) {
     sys_user_portmask_t userPmsk;
     sys_logic_portmask_t setLgPmsk, addPmsk, delPmsk;
     uint32 vlanId, dbSize;
     int32 i;
     uint8 macAddr[CAPA_MAC_BYTE_NUM];
     tpgroup_entry_t *group = NULL;
     igmp_group_entry_t groupEntry;
     uint8 isAdd = TRUE;
     sys_igmp_db_t db;
     uint32 stGroupNum;
     tpgroup_entry_t *ourstGrp = (tpgroup_entry_t *) data_context;

     if (!ourstGrp)
        return SNMP_ERR_RESOURCEUNAVAILABLE;

        SYS_MEM_CLEAR(groupEntry);
        groupEntry.vid = ourstGrp->vlanId;
        if (ourstGrp->mac[0] == 0x33 && ourstGrp->mac[1] == 0x33)
        {
            groupEntry.ipType = MULTICAST_TYPE_IPV4 + 1;
        }
        else
        {
            groupEntry.ipType = MULTICAST_TYPE_IPV4;
        }

        sal_mcast_databaseSize_get(&dbSize);
        if(dbSize == 0)
            return SNMP_ERR_RESOURCEUNAVAILABLE;

        for (i = 0; i < dbSize; i++)
        {
            SYS_MEM_CLEAR(db);
            db.indx = i;
            if(SYS_ERR_OK != sal_mcast_database_get(&db))
                continue;
            if (groupEntry.ipType == db.ipType &&
                groupEntry.vid == db.vid &&
                IGMP_GROUP_ENTRY_STATIC == db.form)
            {
                if (0 == osal_memcmp(ourstGrp->mac, db.mac, CAPA_MAC_BYTE_NUM))
                {
                    groupEntry.dip = db.dip;
                    break;
                }
            }
        }

        if (i == dbSize)
            return SNMP_ERR_RESOURCEUNAVAILABLE;

        LOGIC_PORTMASK_CLEAR_ALL(setLgPmsk);
        LOGIC_PORTMASK_CLEAR_ALL(addPmsk);
        LOGIC_PORTMASK_CLEAR_ALL(delPmsk);

        charstr2userPortMask(val, val_len, &userPmsk);
        userPortMask_reverse(&userPmsk, sizeof(userPmsk));
        UPM2LPM(&userPmsk, &setLgPmsk);

        LOGIC_PORTMASK_ANDNOT(addPmsk, setLgPmsk, db.staticInMbr);
        LOGIC_PORTMASK_ANDNOT(delPmsk, db.staticInMbr, setLgPmsk);

        if(!IS_LOGIC_PORTMASK_CLEAR(addPmsk))
        {
            LOGIC_PORTMASK_COPY(groupEntry.mbr, addPmsk);
            isAdd = TRUE;
            SYS_SNMP_ERR_CHK(sal_mcast_static_group_set(&groupEntry, FILTER_MODE_INCLUDE, isAdd), SNMP_ERR_RESOURCEUNAVAILABLE);

            LOGIC_PORTMASK_COPY(groupEntry.mbr, delPmsk);
            isAdd = FALSE;
            SYS_SNMP_ERR_CHK(sal_mcast_static_group_set(&groupEntry, FILTER_MODE_INCLUDE, isAdd), SNMP_ERR_RESOURCEUNAVAILABLE);
        }

        return SNMP_ERR_NOERROR;  /** XXX: change if an error occurs */
      }
/** XXX: return a data pointer to the data for the dot1qStaticMulticastForbiddenEgressPorts column and set
         ret_len to its proper size in bytes. */
