void *
dot1qVlanStaticTable_create_data_context(netsnmp_variable_list *index_data, int column) {
    vlan_static_entry_t stVlan;
    vlan_static_entry_t *pGet = NULL;

    SYS_MEM_CLEAR(stVlan);
    stVlan.vlanId = *(index_data->val.integer);
    pGet = qbridge_getStVlanEntry(stVlan.vlanId);
    if (pGet)
        return SNMP_ERR_INCONSISTENTVALUE;

    if (IS_VID_INVALID(stVlan.vlanId))
        return SNMP_ERR_WRONGVALUE;

    qBridge_stVlan_creatEntry(&stVlan);

    return qbridge_getStVlanEntry(stVlan.vlanId);
}

