/** XXX: Set the value of the dot1qVlanStaticUntaggedPorts column and return
         SNMP_ERR_NOERROR on success
         SNMP_ERR_XXX     for SNMP deterministic error codes
         SNMP_ERR_GENERR  on generic failures (a last result response). */
      int set_dot1qVlanStaticUntaggedPorts(void *data_context, char *val, size_t val_len) {
       vlan_static_entry_t *ourAdminVlan = (vlan_static_entry_t *)data_context;
        sys_user_portmask_t userPmsk;
        sys_logic_portmask_t setLgPmsk, tmpLogPmsk;
        sys_vlan_adminEntry_t adminVlan;

        if (!ourAdminVlan)
            return SNMP_ERR_RESOURCEUNAVAILABLE;
        SYS_MEM_CLEAR(adminVlan);

        /* get vlan entry by vid */
        SYS_SNMP_ERR_CHK(sal_vlan_adminEntry_get(ourAdminVlan->vlanId, &adminVlan), SNMP_ERR_RESOURCEUNAVAILABLE);
        LOGIC_PORTMASK_CLEAR_ALL(setLgPmsk);
        userPortMask_reverse(&userPmsk, sizeof(userPmsk));
        UPM2LPM(&userPmsk, &setLgPmsk);

        LOGIC_PORTMASK_CLEAR_ALL(tmpLogPmsk);
        LOGIC_PORTMASK_AND(tmpLogPmsk, setLgPmsk, adminVlan.lpmMember);
        if (!IS_LOGIC_PORTMASK_EQUAL(setLgPmsk, tmpLogPmsk))
        {
            return SNMP_ERR_WRONGVALUE;
        }
        //get tag portmbr
        LOGIC_PORTMASK_ANDNOT(adminVlan.lpmMember,adminVlan.lpmMember,adminVlan.lpmUntag);
        LOGIC_PORTMASK_COPY(adminVlan.lpmUntag,setLgPmsk);
        LOGIC_PORTMASK_OR(adminVlan.lpmMember,adminVlan.lpmMember,setLgPmsk);
        SYS_SNMP_ERR_CHK(sal_vlan_adminEntry_set(ourAdminVlan->vlanId, &adminVlan), SNMP_ERR_RESOURCEUNAVAILABLE);

        return SNMP_ERR_NOERROR;  /** XXX: change if an error occurs */
      }
/** XXX: return a data pointer to the data for the dot1qVlanStaticRowStatus column and set
         ret_len to its proper size in bytes. */
      long *get_dot1qVlanStaticRowStatus(void *data_context, size_t *ret_len) {
       vlan_static_entry_t *ourAdminVlan = (vlan_static_entry_t *)data_context;
       *ret_len = SNMP_VAR_INTEGER_LENGTH;
       long_ret = ourAdminVlan->rowStatus;
       return &long_ret;
      }
/** XXX: Set the value of the dot1qVlanStaticRowStatus column and return
         SNMP_ERR_NOERROR on success
         SNMP_ERR_XXX     for SNMP deterministic error codes
         SNMP_ERR_GENERR  on generic failures (a last result response). */
      int set_dot1qVlanStaticRowStatus(void *data_context, long *val, size_t val_len) {
      sys_namestr_t vlanName;
      vlan_static_entry_t *ourAdminVlan = (vlan_static_entry_t *)data_context;
      if (!ourAdminVlan)
            return SNMP_ERR_RESOURCEUNAVAILABLE;

        if (*val == SNMP_ROW_DESTROY ||*val == SNMP_ROW_NOTINSERVICE)
        {
            if (!IS_STATIC_VLAN_EXIST(ourAdminVlan->vlanId))
                return SNMP_ERR_RESOURCEUNAVAILABLE;

            SYS_SNMP_ERR_CHK(sal_vlan_adminEntry_destroy(ourAdminVlan->vlanId), SNMP_ERR_RESOURCEUNAVAILABLE);
        }
        else if (*val  == SNMP_ROW_CREATEANDWAIT ||
                    *val  == SNMP_ROW_CREATEANDGO ||
                    *val  == SNMP_ROW_ACTIVE )
        {
             if (IS_STATIC_VLAN_EXIST(ourAdminVlan->vlanId))
                return SNMP_ERR_RESOURCEUNAVAILABLE;

            osal_memset(&vlanName,0,sizeof(vlanName));
            SYS_SNMP_ERR_CHK(sal_vlan_nameStr_get(ourAdminVlan->vlanId, "VLAN", &vlanName),SNMP_ERR_RESOURCEUNAVAILABLE);
            SYS_SNMP_ERR_CHK(sal_vlan_adminEntry_create(ourAdminVlan->vlanId, &vlanName), SNMP_ERR_RESOURCEUNAVAILABLE);
        }

        return SNMP_ERR_NOERROR;  /** XXX: change if an error occurs */
      }


